// Compact board listing for the match agent
const lines = $input.all().map(i => `${i.json.id} | ${i.json.name}`);
return [{ json: { boardText: lines.join('\n'), count: lines.length } }];

// Get Claude's text block (skip the "thinking" block)
const content = $input.first().json.content || [];
const textBlock = content.find(c => c.type === 'text') || content[0] || {};
const raw = (textBlock.text || '').trim();

// Each task starts with a "name:" line -- split on it
// (works whether or not ===TASK=== markers are present)
const chunks = raw.split(/(?=^[ \t]*name:)/im).filter(c => /name:/i.test(c));

const tasks = chunks.map(block => {
  const name = ((block.match(/name:\s*(.+)/i) || [])[1] || '').trim();
  const priority = Number((block.match(/priority:\s*(\d)/i) || [])[1] || 3);
  const tags = ((block.match(/tags:\s*(.+)/i) || [])[1] || '')
    .split(',').map(t => t.trim()).filter(Boolean);
  let description = (block.match(/description:\s*([\s\S]*)/i) || [])[1] || '';
  description = description.replace(/={3,}\s*TASK\s*={3,}[\s\S]*$/i, '').replace(/={3,}\s*$/, '').trim();
  return { name, priority, tags, description };
})
// drop junk chunks: the name must be meaningful
.filter(t => t.name.replace(/[\[\]\s]/g, '').length > 3);

return tasks.map(t => ({ json: t }));

// Parse the match agent's decision and merge with the meeting point
const content = $json.content || [];
const tb = content.find(c => c.type === 'text') || content[0] || {};
const t = tb.text || '';
const decision = ((t.match(/DECISION:\s*(NEW|UPDATE)/i) || [])[1] || 'NEW').toUpperCase();
const taskId = ((t.match(/TASK_ID:\s*([a-z0-9]+)/i) || [])[1] || '');
let confidence = Number((t.match(/CONFIDENCE:\s*([\d.]+)/i) || [])[1] || 0);
const reason = ((t.match(/REASON:\s*(.+)/i) || [])[1] || '').trim();
const item = $('Parse tasks').item.json;
const board = $('Board summary').first().json.boardText || '';
const is_update = decision === 'UPDATE';
if (is_update && (!taskId || !board.includes(taskId))) confidence = 0;
const comment = (item.description || item.name || '').trim();
const action_summary = is_update
  ? ('comment on existing task ' + taskId + ': ' + item.name)
  : ('create a new task: ' + item.name);
return { json: Object.assign({}, item, { is_update, target_id: taskId, confidence, reason, comment, action_summary }) };

