const fs = require('fs');
const j = $json;
const entry = {
  ts: new Date().toISOString(),
  point: j.name,
  decision: j.is_update ? 'UPDATE' : 'NEW',
  target: j.target_id || null,
  confidence: j.confidence,
  reason: j.reason,
  gate: (j.confidence >= 0.8) ? 'auto' : 'human'
};
fs.appendFileSync('evals/decision_log.jsonl', JSON.stringify(entry) + '\n');
return { json: j };
